#include <bits/stdc++.h>
using namespace std;
int t,n,a[100005];
int main(){
    scanf("%d",&t);
    while(t--){
        scanf("%d",&n);
        for(int i=1;i<=n;i++)
            scanf("%d",&a[i]);
        sort(a+1,a+n+1);
        int ans=1;
        long long sum=0,num=0;
        for(int i=1;i<=n;i++)
            if(a[i]>=ans)
                sum+=a[i]-ans,ans++;
            else
                num+=a[i]-1;
        if(sum<=ans && ans<=sum+num)
            ans++;
        printf("%d\n",ans);
    }
    return 0;
}
